        modifiers in any::<MouseModifiers>(),
        x in 1u8..=223,
        y in 1u8..=223,
        motion in any::<bool>(),
    ) -> NormalMouseEvent {
        NormalMouseEvent { button, modifiers, x, y, motion }
    }
}

impl NormalMouseEvent {
    pub fn to_bytes(&self) -> Vec<u8> {
        let mut cb = match self.button {
            MouseButton::Left => 0,
            MouseButton::Middle => 1,
            MouseButton::Right => 2,
            MouseButton::WheelUp => 64,
            MouseButton::WheelDown => 65,
            _ => 3,
        };

        cb += self.modifiers.to_bits();
        if self.motion { cb |= 32; }

        vec![
            0x1B, b'[', b'M',
            cb + 32,
            self.x + 32,
            self.y + 32,
        ]
    }
}
