proptest! {
    /// Property: Non-canonical input normalizes to canonical form
    #[test]
    fn normalization_to_canonical(
        seq in arb_non_canonical_key_sequence()
    ) {
        let bytes = seq.to_bytes();
        let parsed = KeyParser::parse(&bytes);

        prop_assume!(parsed.is_some());
        let (key, _) = parsed.unwrap();

        // Serialize should produce canonical form
        let canonical = KeySerializer::serialize(&key);

        // Reparsing canonical should give same key
        let (canonical_key, _) = KeyParser::parse(&canonical).unwrap();
        prop_assert_eq!(key, canonical_key);

        // Canonical form should be stable
        let recanonical = KeySerializer::serialize(&canonical_key);
        prop_assert_eq!(canonical, recanonical, "Canonical form should be stable");
