    /// Property: Multiple equivalent representations parse to same key
    #[test]
    fn equivalent_representations(
        key_type in arb_key_type(),
    ) {
        // Generate all valid representations of this key type
        let representations = key_type.all_valid_representations();

        let mut parsed_keys = vec![];
        for repr in &representations {
            if let Some((key, _)) = KeyParser::parse(repr) {
                parsed_keys.push(key);
            }
        }

        // All should parse to the same key
        if !parsed_keys.is_empty() {
            let first = &parsed_keys[0];
            for key in &parsed_keys[1..] {
                prop_assert_eq!(key, first, "All representations should parse to same key");
